cypher_attempts.cypher:
MATCH (s:Statement:Verified)
WHERE (
    toLower(s.object_text) CONTAINS 'fire extinguisher' OR
    toLower(s.subject_text) CONTAINS 'fire extinguisher' OR
    EXISTS {
        MATCH (s)-[:HAS_OBJECT|HAS_SUBJECT]->(c:Concept)
        WHERE toLower(c.label) CONTAINS 'fire extinguisher'
    }
)
AND (
    toLower(s.predicate_text) CONTAINS 'inspect' OR
    EXISTS {
        MATCH (s)-[:HAS_PREDICATE]->(c:Concept)
        WHERE toLower(c.label) CONTAINS 'inspect'
    }
)
AND (
    ANY(cond IN s.condition_text WHERE toLower(cond) CONTAINS 'annual' OR toLower(cond) CONTAINS 'every year') OR
    toLower(s.anchor) CONTAINS 'annual' OR toLower(s.anchor) CONTAINS 'every year'
)
AND s.statement_class = 'DEONTIC'
AND s.modality = 'OBLIGATION'
RETURN DISTINCT s.statement_id AS statement_id

